  1	import {
  2	  GreenCheckCircleIcon,
  3	  K8sModel,
  4	  K8sResourceKind,
  5	  ListPageBody,
  6	  ListPageFilter,
  7	  ListPageHeader,
  8	  PrometheusEndpoint,
  9	  RedExclamationCircleIcon,
 10	  ResourceLink,
 11	  RowFilter,
 12	  RowProps,
 13	  TableColumn,
 14	  Timestamp,
 15	  useK8sWatchResource,
 16	  useListPageFilter,
 17	  VirtualizedTable,
 18	} from '@openshift-console/dynamic-plugin-sdk';
 19	import {
 20	  Alert,
 21	  AlertActionCloseButton,
 22	  Breadcrumb,
 23	  BreadcrumbItem,
 24	  DescriptionList,
 25	  DescriptionListDescription,
 26	  DescriptionListGroup,
 27	  DescriptionListTerm,
 28	  Divider,
 29	  Grid,
 30	  GridItem,
 31	  PageBreadcrumb,
 32	  PageGroup,
 33	  PageSection,
 34	  PageSectionVariants,
 35	  Title,
 36	  Tooltip,
 37	} from '@patternfly/react-core';
 38	import { sortable, Td } from '@patternfly/react-table';
 39	import { find, includes, isEmpty } from 'lodash-es';
 40	import * as React from 'react';
 41	import { Helmet } from 'react-helmet';
 42	import { useTranslation } from 'react-i18next';
 43	import { Link, Route, Switch, useRouteMatch } from 'react-router-dom';
 44	
 45	import {
 46	  NamespaceModel,
 47	  PodModel,
 48	  PodMonitorModel,
 49	  ServiceModel,
 50	  ServiceMonitorModel,
 51	} from './console/models';
 52	import { usePoll } from './console/utils/poll-hook';
 53	import { useSafeFetch } from './console/utils/safe-fetch-hook';
 54	
 55	import { useBoolean } from './hooks/useBoolean';
 56	import { Labels } from './labels';
 57	import { AlertSource, PrometheusAPIError, Target } from './types';
 58	import { fuzzyCaseInsensitive, targetSource } from './utils';
 59	import { PROMETHEUS_BASE_PATH } from './console/graphs/helpers';
 60	import { LoadingInline } from './console/console-shared/src/components/loading/LoadingInline';
 61	import { StatusBox } from './console/console-shared/src/components/status/StatusBox';
 62	import { EmptyBox } from './console/console-shared/src/components/empty-state/EmptyBox';
 63	import { LabelSelector } from './console/module/k8s/label-selector';
 64	
 65	enum MonitorType {
 66	  ServiceMonitor = 'serviceMonitor',
 67	  PodMonitor = 'podMonitor',
 68	}
 69	
 70	const ServiceMonitorsWatchContext = React.createContext([]);
 71	const ServicesWatchContext = React.createContext([]);
 72	
 73	const PodMonitorsWatchContext = React.createContext([]);
 74	const PodsWatchContext = React.createContext([]);
 75	
 76	const getReference = ({ group, version, kind }) => [group || 'core', version, kind].join('~');
 77	
 78	export const getReferenceForModel = (model: K8sModel) =>
 79	  getReference({ group: model.apiGroup, version: model.apiVersion, kind: model.kind });
 80	
 81	const PodMonitor: React.FC<{ target: Target }> = ({ target }) => {
 82	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 83	
 84	  const [podMonitors, podMonitorsLoaded, podMonitorsLoadError] =
 85	    React.useContext(PodMonitorsWatchContext);
 86	  const [pods, podsLoaded] = React.useContext(PodsWatchContext);
 87	
 88	  if (podMonitorsLoadError) {
 89	    return (
 90	      <>
 91	        <RedExclamationCircleIcon /> {t('Error')}
 92	      </>
 93	    );
 94	  }
 95	
 96	  if (!podsLoaded || !podMonitorsLoaded) {
 97	    return <LoadingInline />;
 98	  }
 99	
100	  // First find the pod that corresponds to the target
101	  const pod = find(
102	    pods,
103	    ({ metadata }) =>
104	      metadata.name === target?.labels?.pod && metadata.namespace === target?.labels?.namespace,
105	  );
106	
107	  // Now find the pod monitor that corresponds to the pod
108	  const podMonitor = find(
109	    podMonitors,
110	    ({ metadata, spec }) =>
111	      pod &&
112	      target.scrapePool.includes(`/${metadata.namespace}/${metadata.name}/`) &&
113	      ((spec.selector.matchLabels === undefined && spec.selector.matchExpressions === undefined) ||
114	        new LabelSelector(spec.selector).matchesLabels(pod.metadata.labels ?? {})) &&
115	      (spec.namespaceSelector?.matchNames === undefined ||
116	        includes(spec.namespaceSelector?.matchNames, pod.metadata.namespace)),
117	  );
118	
119	  if (!podMonitor) {
120	    return <>-</>;
121	  }
122	
123	  return (
124	    <ResourceLink
125	      kind={getReferenceForModel(PodMonitorModel)}
126	      name={podMonitor.metadata.name}
127	      namespace={podMonitor.metadata.namespace}
128	    />
129	  );
130	};
131	
132	const ServiceMonitor: React.FC<{ target: Target }> = ({ target }) => {
133	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
134	
135	  const [monitors, monitorsLoaded, monitorsLoadError] = React.useContext(
136	    ServiceMonitorsWatchContext,
137	  );
138	  const [services, servicesLoaded] = React.useContext(ServicesWatchContext);
139	
140	  if (monitorsLoadError) {
141	    return (
142	      <>
143	        <RedExclamationCircleIcon /> {t('Error')}
144	      </>
145	    );
146	  }
147	
148	  if (!servicesLoaded || !monitorsLoaded) {
149	    return <LoadingInline />;
150	  }
151	
152	  // First find the service that corresponds to the target
153	  const service = find(
154	    services,
155	    ({ metadata }) =>
156	      metadata.name === target?.labels?.service && metadata.namespace === target?.labels?.namespace,
157	  );
158	
159	  // Now find the service monitor that corresponds to the service
160	  const monitor = find(
161	    monitors,
162	    ({ metadata, spec }) =>
163	      service &&
164	      target.scrapePool.includes(`/${metadata.namespace}/${metadata.name}/`) &&
165	      ((spec.selector.matchLabels === undefined && spec.selector.matchExpressions === undefined) ||
166	        new LabelSelector(spec.selector).matchesLabels(service.metadata.labels ?? {})) &&
167	      (spec.namespaceSelector?.matchNames === undefined ||
168	        includes(spec.namespaceSelector?.matchNames, service.metadata.namespace)),
169	  );
170	
171	  if (!monitor) {
172	    return <>-</>;
173	  }
174	
175	  return (
176	    <ResourceLink
177	      kind={getReferenceForModel(ServiceMonitorModel)}
178	      name={monitor.metadata.name}
179	      namespace={monitor.metadata.namespace}
180	    />
181	  );
182	};
183	
184	const Health: React.FC<{ health: 'up' | 'down' }> = React.memo(({ health }) => {
185	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
186	
187	  return health === 'up' ? (
188	    <>
189	      <GreenCheckCircleIcon /> {t('Up')}
190	    </>
191	  ) : (
192	    <>
193	      <RedExclamationCircleIcon /> {t('Down')}
194	    </>
195	  );
196	});
197	
198	type WatchErrorAlertProps = {
199	  loadError: { code: number; message: string };
200	  title: string;
201	};
202	
203	const WatchErrorAlert: React.FC<WatchErrorAlertProps> = ({ loadError, title }) => {
204	  const [showError, , , hideError] = useBoolean(true);
205	
206	  if (!showError) {
207	    return null;
208	  }
209	
210	  return (
211	    <Alert
212	      title={title}
213	      variant="danger"
214	      actionClose={<AlertActionCloseButton onClose={hideError} />}
215	    >
216	      {loadError.message}
217	    </Alert>
218	  );
219	};
220	
221	type DetailsProps = {
222	  loaded: boolean;
223	  loadError: string;
224	  targets: Target[];
225	};
226	
227	const Details: React.FC<DetailsProps> = ({ loaded, loadError, targets }) => {
228	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
229	
230	  const match = useRouteMatch<{ scrapeUrl?: string }>();
231	
232	  let scrapeUrl = '';
233	  let target: Target | undefined;
234	  if (match?.params?.scrapeUrl) {
235	    try {
236	      scrapeUrl = atob(match?.params?.scrapeUrl);
237	      target = find(targets, { scrapeUrl });
238	    } catch {
239	      // Leave scrapeUrl and target unset
240	    }
241	  }
242	
243	  const isServiceMonitor: boolean =
244	    target && target.scrapePool.includes(MonitorType.ServiceMonitor);
245	  const isPodMonitor: boolean = target && target.scrapePool.includes(MonitorType.PodMonitor);
246	
247	  const [, , serviceMonitorsLoadError] = React.useContext(ServiceMonitorsWatchContext);
248	  const [, , podMonitorsLoadError] = React.useContext(PodMonitorsWatchContext);
249	
250	  return (
251	    <>
252	      <Helmet>
253	        <title>{t('Target details')}</title>
254	      </Helmet>
255	      <PageGroup>
256	        <PageBreadcrumb>
257	          <Breadcrumb>
258	            <BreadcrumbItem>
259	              <Link className="pf-v6-c-breadcrumb__link" to="/monitoring/targets">
260	                {t('Targets')}
261	              </Link>
262	            </BreadcrumbItem>
263	            <BreadcrumbItem isActive>{t('Target details')}</BreadcrumbItem>
264	          </Breadcrumb>
265	        </PageBreadcrumb>
266	        <PageSection variant={PageSectionVariants.light}>
267	          <Title headingLevel="h1">
268	            <div className="pf-v6-u-text-break-word">{scrapeUrl}</div>
269	          </Title>
270	        </PageSection>
271	      </PageGroup>
272	      <Divider />
273	      <StatusBox data={target} label="target" loaded={loaded} loadError={loadError}>
274	        <PageSection variant={PageSectionVariants.light}>
275	          <Title headingLevel="h2">{t('Target details')}</Title>
276	          {isServiceMonitor && serviceMonitorsLoadError && (
277	            <WatchErrorAlert
278	              loadError={serviceMonitorsLoadError}
279	              title={t('Error loading service monitor data')}
280	            />
281	          )}
282	          {isPodMonitor && podMonitorsLoadError && (
283	            <WatchErrorAlert
284	              loadError={podMonitorsLoadError}
285	              title={t('Error loading pod monitor data')}
286	            />
287	          )}
288	          <Grid sm={12} md={6}>
289	            <GridItem>
290	              <DescriptionList>
291	                <DescriptionListGroup>
292	                  <DescriptionListTerm>{t('Endpoint')}</DescriptionListTerm>
293	                  <DescriptionListDescription>{scrapeUrl}</DescriptionListDescription>
294	                </DescriptionListGroup>
295	                <DescriptionListGroup>
296	                  <DescriptionListTerm>{t('Namespace')}</DescriptionListTerm>
297	                  <DescriptionListDescription>
298	                    <ResourceLink kind="Namespace" name={target?.labels?.namespace} />
299	                  </DescriptionListDescription>
300	                </DescriptionListGroup>
301	                <DescriptionListGroup>
302	                  <DescriptionListTerm>{t('Labels')}</DescriptionListTerm>
303	                  <DescriptionListDescription>
304	                    <Labels kind="metricstarget" labels={target?.labels} />
305	                  </DescriptionListDescription>
306	                </DescriptionListGroup>
307	                <DescriptionListGroup>
308	                  <DescriptionListTerm>{t('Last scrape')}</DescriptionListTerm>
309	                  <DescriptionListDescription>
310	                    <Timestamp timestamp={target?.lastScrape} />
311	                  </DescriptionListDescription>
312	                </DescriptionListGroup>
313	                {target?.lastError && (
314	                  <Alert title={t('Scrape failed')} variant="danger">
315	                    {target?.lastError}
316	                  </Alert>
317	                )}
318	              </DescriptionList>
319	            </GridItem>
320	            <GridItem>
321	              <DescriptionList>
322	                <DescriptionListGroup>
323	                  <DescriptionListTerm>{t('Status')}</DescriptionListTerm>
324	                  <DescriptionListDescription>
325	                    <Health health={target?.health} />
326	                  </DescriptionListDescription>
327	                </DescriptionListGroup>
328	                <DescriptionListGroup>
329	                  <DescriptionListTerm>{t('Monitor')}</DescriptionListTerm>
330	                  {isServiceMonitor && (
331	                    <DescriptionListDescription>
332	                      <ServiceMonitor target={target} />
333	                    </DescriptionListDescription>
334	                  )}
335	                  {isPodMonitor && (
336	                    <DescriptionListDescription>
337	                      <PodMonitor target={target} />
338	                    </DescriptionListDescription>
339	                  )}
340	                  {!isServiceMonitor && !isPodMonitor && (
341	                    <DescriptionListDescription>
342	                      <>-</>
343	                    </DescriptionListDescription>
344	                  )}
345	                </DescriptionListGroup>
346	              </DescriptionList>
347	            </GridItem>
348	          </Grid>
349	        </PageSection>
350	      </StatusBox>
351	    </>
352	  );
353	};
354	
355	const tableClasses = [
356	  'pf-u-w-25-on-md', // Endpoint
357	  'pf-u-w-16-on-md', // Monitor
358	  '', // Status
359	  'pf-u-w-16-on-md', // Namespace
360	  'pf-m-hidden pf-m-visible-on-md', // Last Scrape
361	  'pf-m-hidden pf-m-visible-on-md', // Scrape Duration
362	];
363	
364	const Row: React.FC<RowProps<Target>> = ({ obj }) => {
365	  const { health, labels, lastError, lastScrape, lastScrapeDuration, scrapePool, scrapeUrl } = obj;
366	
367	  const isServiceMonitor: boolean = scrapePool?.includes(MonitorType.ServiceMonitor);
368	  const isPodMonitor: boolean = scrapePool?.includes(MonitorType.PodMonitor);
369	
370	  return (
371	    <>
372	      <Td className={tableClasses[0]}>
373	        <Link to={`./targets/${btoa(scrapeUrl)}`}>{scrapeUrl}</Link>
374	      </Td>
375	      <Td className={tableClasses[1]}>
376	        {isServiceMonitor && <ServiceMonitor target={obj} />}
377	        {isPodMonitor && <PodMonitor target={obj} />}
378	        {!isServiceMonitor && !isPodMonitor && <>-</>}
379	      </Td>
380	      <Td className={tableClasses[2]}>
381	        {health === 'up' ? (
382	          <Health health="up" />
383	        ) : (
384	          <Tooltip content={lastError}>
385	            <span>
386	              <Health health="down" />
387	            </span>
388	          </Tooltip>
389	        )}
390	      </Td>
391	      <Td className={tableClasses[3]}>
392	        {labels?.namespace && (
393	          <ResourceLink inline kind={NamespaceModel.kind} name={labels?.namespace} />
394	        )}
395	      </Td>
396	      <Td className={tableClasses[4]}>
397	        <Timestamp timestamp={lastScrape} />
398	      </Td>
399	      <Td className={tableClasses[5]}>
400	        {lastScrapeDuration ? `${(1000 * lastScrapeDuration).toFixed(1)} ms` : '-'}
401	      </Td>
402	    </>
403	  );
404	};
405	
406	type ListProps = {
407	  data: Target[];
408	  loaded: boolean;
409	  loadError: string;
410	  unfilteredData: Target[];
411	};
412	
413	const List: React.FC<ListProps> = ({ data, loaded, loadError, unfilteredData }) => {
414	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
415	
416	  const columns = React.useMemo<TableColumn<Target>[]>(
417	    () => [
418	      {
419	        id: 'scrapeUrl',
420	        title: t('Endpoint'),
421	        sort: 'scrapeUrl',
422	        transforms: [sortable],
423	        props: { className: tableClasses[0] },
424	      },
425	      {
426	        id: 'monitor',
427	        title: t('Monitor'),
428	        props: { className: tableClasses[1] },
429	      },
430	      {
431	        id: 'health',
432	        title: t('Status'),
433	        sort: 'health',
434	        transforms: [sortable],
435	        props: { className: tableClasses[2] },
436	      },
437	      {
438	        id: 'namespace',
439	        title: t('Namespace'),
440	        sort: 'labels.namespace',
441	        transforms: [sortable],
442	        props: { className: tableClasses[3] },
443	      },
444	      {
445	        id: 'lastScrape',
446	        title: t('Last Scrape'),
447	        sort: 'lastScrape',
448	        transforms: [sortable],
449	        props: { className: tableClasses[4] },
450	      },
451	      {
452	        id: 'lastScrapeDuration',
453	        title: t('Scrape Duration'),
454	        sort: 'lastScrapeDuration',
455	        transforms: [sortable],
456	        props: { className: tableClasses[5] },
457	      },
458	    ],
459	    [t],
460	  );
461	
462	  return (
463	    <VirtualizedTable<Target>
464	      aria-label={t('Metrics targets')}
465	      label={t('Metrics targets')}
466	      columns={columns}
467	      data={data}
468	      loaded={loaded}
469	      loadError={loadError}
470	      Row={Row}
471	      unfilteredData={unfilteredData}
472	      NoDataEmptyMsg={() => {
473	        return <EmptyBox label={t('Metrics targets')} />;
474	      }}
475	    />
476	  );
477	};
478	
479	type ListPageProps = {
480	  loaded: boolean;
481	  loadError: string;
482	  targets: Target[];
483	};
484	
485	const ListPage: React.FC<ListPageProps> = ({ loaded, loadError, targets }) => {
486	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
487	
488	  const [, , serviceMonitorsLoadError] = React.useContext(ServiceMonitorsWatchContext);
489	  const [, , podMonitorsLoadError] = React.useContext(PodMonitorsWatchContext);
490	
491	  const nameFilter: RowFilter = {
492	    filter: (filter, target: Target) =>
493	      fuzzyCaseInsensitive(filter.selected?.[0], target.scrapeUrl) ||
494	      fuzzyCaseInsensitive(filter.selected?.[0], target.labels?.namespace),
495	    items: [],
496	    type: 'name',
497	  } as RowFilter;
498	
499	  const rowFilters: RowFilter[] = [
500	    {
501	      filter: (filter, target: Target) =>
502	        filter.selected?.includes(target.health) || isEmpty(filter.selected),
503	      filterGroupName: t('Status'),
504	      items: [
505	        { id: 'up', title: t('Up') },
506	        { id: 'down', title: t('Down') },
507	      ],
508	      reducer: (target: Target) => target?.health,
509	      type: 'observe-target-health',
510	    },
511	    {
512	      filter: (filter, target: Target) =>
513	        filter.selected?.includes(targetSource(target)) || isEmpty(filter.selected),
514	      filterGroupName: t('Source'),
515	      items: [
516	        { id: AlertSource.Platform, title: t('Platform') },
517	        { id: AlertSource.User, title: t('User') },
518	      ],
519	      reducer: targetSource,
520	      type: 'observe-target-source',
521	    },
522	  ];
523	
524	  const allFilters: RowFilter[] = [nameFilter, ...rowFilters];
525	
526	  const [staticData, filteredData, onFilterChange] = useListPageFilter(targets, allFilters);
527	
528	  const title = t('Metrics targets');
529	
530	  return (
531	    <>
532	      <Helmet>
533	        <title>{title}</title>
534	      </Helmet>
535	      <ListPageHeader title={title} />
536	      {/*
537	      // eslint-disable-next-line @typescript-eslint/ban-ts-comment
538	      // @ts-ignore TODO */}
539	      <ListPageBody>
540	        {loadError && (
541	          <Alert title={t('Error loading latest targets data')} variant="danger">
542	            {loadError}
543	          </Alert>
544	        )}
545	        {serviceMonitorsLoadError && (
546	          <WatchErrorAlert
547	            loadError={serviceMonitorsLoadError}
548	            title={t('Error loading service monitor data')}
549	          />
550	        )}
551	        {podMonitorsLoadError && (
552	          <WatchErrorAlert
553	            loadError={podMonitorsLoadError}
554	            title={t('Error loading pod monitor data')}
555	          />
556	        )}
557	        <ListPageFilter
558	          data={staticData}
559	          // eslint-disable-next-line @typescript-eslint/ban-ts-comment
560	          // @ts-ignore TODO
561	          labelFilter="observe-target-labels"
562	          labelPath="labels"
563	          loaded={loaded}
564	          nameFilterPlaceholder={t('Search by endpoint or namespace...')}
565	          nameFilterTitle={t('Text')}
566	          onFilterChange={onFilterChange}
567	          rowFilters={rowFilters}
568	        />
569	        <List
570	          data={filteredData ?? []}
571	          loaded={loaded}
572	          loadError={loadError}
573	          unfilteredData={targets}
574	        />
575	      </ListPageBody>
576	    </>
577	  );
578	};
579	
580	const POLL_INTERVAL = 15 * 1000;
581	
582	export const TargetsUI: React.FC = () => {
583	  const [error, setError] = React.useState<PrometheusAPIError>();
584	  const [loaded, setLoaded] = React.useState(false);
585	  const [targets, setTargets] = React.useState<Target[]>();
586	
587	  const servicesWatch = useK8sWatchResource<K8sResourceKind[]>({
588	    isList: true,
589	    kind: ServiceModel.kind,
590	  });
591	
592	  const monitorsWatch = useK8sWatchResource<K8sResourceKind[]>({
593	    isList: true,
594	    kind: getReferenceForModel(ServiceMonitorModel),
595	  });
596	
597	  const podsWatch = useK8sWatchResource<K8sResourceKind[]>({
598	    isList: true,
599	    kind: PodModel.kind,
600	  });
601	
602	  const podMonitorsWatch = useK8sWatchResource<K8sResourceKind[]>({
603	    isList: true,
604	    kind: getReferenceForModel(PodMonitorModel),
605	  });
606	
607	  // eslint-disable-next-line react-hooks/exhaustive-deps
608	  const safeFetch = React.useCallback(useSafeFetch(), []);
609	
610	  const tick = () =>
611	    safeFetch(`${PROMETHEUS_BASE_PATH}/${PrometheusEndpoint.TARGETS}?state=active`)
612	      .then((response) => {
613	        setError(undefined);
614	        setLoaded(true);
615	        setTargets(response?.data?.activeTargets);
616	      })
617	      .catch((err) => {
618	        if (err.name !== 'AbortError') {
619	          setError(err);
620	          setLoaded(true);
621	        }
622	      });
623	
624	  usePoll(tick, POLL_INTERVAL);
625	
626	  const loadError = error?.json?.error || error?.message;
627	
628	  return (
629	    <ServiceMonitorsWatchContext.Provider value={monitorsWatch}>
630	      <ServicesWatchContext.Provider value={servicesWatch}>
631	        <PodMonitorsWatchContext.Provider value={podMonitorsWatch}>
632	          <PodsWatchContext.Provider value={podsWatch}>
633	            <Switch>
634	              <Route path="/monitoring/targets" exact>
635	                <ListPage loaded={loaded} loadError={loadError} targets={targets} />
636	              </Route>
637	              <Route path="/monitoring/targets/:scrapeUrl?" exact>
638	                <Details loaded={loaded} loadError={loadError} targets={targets} />
639	              </Route>
640	              <Route path="/virt-monitoring/targets" exact>
641	                <ListPage loaded={loaded} loadError={loadError} targets={targets} />
642	              </Route>
643	              <Route path="/virt-monitoring/targets/:scrapeUrl?" exact>
644	                <Details loaded={loaded} loadError={loadError} targets={targets} />
645	              </Route>
646	            </Switch>
647	          </PodsWatchContext.Provider>
648	        </PodMonitorsWatchContext.Provider>
649	      </ServicesWatchContext.Provider>
650	    </ServiceMonitorsWatchContext.Provider>
651	  );
652	};

