104	  );
105	
106	  // Now find the pod monitor that corresponds to the pod
107	  const podMonitor = find(
108	    podMonitors,
109	    ({ metadata, spec }) =>
110	      pod &&
111	      target.scrapePool.includes(`/${metadata.namespace}/${metadata.name}/`) &&
112	      ((spec.selector.matchLabels === undefined && spec.selector.matchExpressions === undefined) ||
113	        new LabelSelector(spec.selector).matchesLabels(pod.metadata.labels ?? {})) &&
114	      (spec.namespaceSelector?.matchNames === undefined ||
115	        includes(spec.namespaceSelector?.matchNames, pod.metadata.namespace)),
116	  );
