581	const POLL_INTERVAL = 15 * 1000;
582	
583	export const TargetsUI: React.FC = () => {
584	  const [error, setError] = React.useState<PrometheusAPIError>();
585	  const [loaded, setLoaded] = React.useState(false);
586	  const [targets, setTargets] = React.useState<Target[]>();
587	
588	  const servicesWatch = useK8sWatchResource<K8sResourceKind[]>({
589	    isList: true,
590	    kind: ServiceModel.kind,
591	  });
592	
593	  const monitorsWatch = useK8sWatchResource<K8sResourceKind[]>({
594	    isList: true,
595	    kind: getReferenceForModel(ServiceMonitorModel),
596	  });
597	
598	  const podsWatch = useK8sWatchResource<K8sResourceKind[]>({
599	    isList: true,
600	    kind: PodModel.kind,
601	  });
602	
603	  const podMonitorsWatch = useK8sWatchResource<K8sResourceKind[]>({
604	    isList: true,
605	    kind: getReferenceForModel(PodMonitorModel),
606	  });
607	
608	  // eslint-disable-next-line react-hooks/exhaustive-deps
609	  const safeFetch = React.useCallback(useSafeFetch(), []);
610	
611	  const tick = () =>
612	    safeFetch(`${PROMETHEUS_BASE_PATH}/${PrometheusEndpoint.TARGETS}?state=active`)
613	      .then((response) => {
614	        setError(undefined);
615	        setLoaded(true);
616	        setTargets(response?.data?.activeTargets);
617	      })
618	      .catch((err) => {
619	        if (err.name !== 'AbortError') {
620	          setError(err);
621	          setLoaded(true);
622	        }
623	      });
624	
625	  usePoll(tick, POLL_INTERVAL);
626	
627	  const loadError = error?.json?.error || error?.message;
628	
629	  return (
630	    <ServiceMonitorsWatchContext.Provider value={monitorsWatch}>
631	      <ServicesWatchContext.Provider value={servicesWatch}>
632	        <PodMonitorsWatchContext.Provider value={podMonitorsWatch}>
633	          <PodsWatchContext.Provider value={podsWatch}>
634	            <Switch>
635	              <Route path="/monitoring/targets" exact>
636	                <ListPage loaded={loaded} loadError={loadError} targets={targets} />
637	              </Route>
638	              <Route path="/monitoring/targets/:scrapeUrl?" exact>
639	                <Details loaded={loaded} loadError={loadError} targets={targets} />
640	              </Route>
641	              <Route path="/virt-monitoring/targets" exact>
642	                <ListPage loaded={loaded} loadError={loadError} targets={targets} />
643	              </Route>
644	              <Route path="/virt-monitoring/targets/:scrapeUrl?" exact>
645	                <Details loaded={loaded} loadError={loadError} targets={targets} />
646	              </Route>
647	            </Switch>
648	          </PodsWatchContext.Provider>
649	        </PodMonitorsWatchContext.Provider>
650	      </ServicesWatchContext.Provider>
651	    </ServiceMonitorsWatchContext.Provider>
652	  );
653	};

